    AND LOWER(first_name) = LOWER(rec.first_name) 
    AND LOWER(last_name) = LOWER(rec.last_name) 
    LIMIT 1;
    
    IF v_client_id IS NOT NULL THEN
      UPDATE public.appointments 
      SET client_id = v_client_id 
      WHERE user_id = '8ac58031-b40a-42ab-b108-e75a4e218ece' 
      AND operator_id = rec.op_id::uuid 
      AND start_time = rec.start_ts 
      AND client_id IS NULL 
      AND deleted_at IS NULL;
      v_updated := v_updated + 1;
    END IF;
  END LOOP;
  RAISE NOTICE 'Updated % appointments with client_id', v_updated;
END $$;